function solve(m, n, waitCost) {
    const pq = [];
    const dp = new Array(m).fill().map(() => new Array(n).fill().map(() => new Map()));
    dp[0][0].set(1, 1);
    pq.push({ cost: 1, i: 0, j: 0, t: 1 });

    while (pq.length > 0) {
        pq.sort((a, b) => a.cost - b.cost);
        const current = pq.shift();
        const cost = current.cost;
        const i = current.i;
        const j = current.j;
        const t = current.t;

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (dp[i][j].has(t) && dp[i][j].get(t) < cost) {
            continue;
        }

        if (t % 2 === 1) {
            const moves = [];
            if (i + 1 < m) moves.push([i + 1, j]);
            if (j + 1 < n) moves.push([i, j + 1]);

            for (const [new_i, new_j] of moves) {
                const new_time = t + 1;
                const entry_cost = (new_i + 1) * (new_j + 1);
                const new_cost = cost + entry_cost;

                if (!dp[new_i][new_j].has(new_time) || dp[new_i][new_j].get(new_time) > new_cost) {
                    dp[new_i][new_j].set(new_time, new_cost);
                    pq.push({ cost: new_cost, i: new_i, j: new_j, t: new_time });
                }
            }
        } else {
            const new_time = t + 1;
            const wait_cost = waitCost[i][j];
            const new_cost = cost + wait_cost;

            if (!dp[i][j].has(new_time) || dp[i][j].get(new_time) > new_cost) {
                dp[i][j].set(new_time, new_cost);
                pq.push({ cost: new_cost, i: i, j: j, t: new_time });
            }
        }
    }

    return -1;
}

