```java
import java.util.*;

public class Solution {
    public static long solve(long m, long n, long[][] waitCost) {
        int rows = (int) m;
        int cols = (int) n;
        Map<Long, Long>[][] dp = new HashMap[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                dp[i][j] = new HashMap<>();
            }
        }

        PriorityQueue<State> pq = new PriorityQueue<>();
        pq.offer(new State(1, 0, 0, 1));
        dp[0][0].put(1L, 1L);

        while (!pq.isEmpty()) {
            State current = pq.poll();
            long cost = current.cost;
            int i = current.i;
            int j = current.j;
            long time = current.time;

            if (i == rows - 1 && j == cols - 1) {
                return cost;
            }

            if (dp[i][j].containsKey(time) && dp[i][j].get(time) < cost) {
                continue;
            }

            if (time % 2 == 1) {
                int[] di = {1, 0};
                int[] dj = {0, 1};
                for (int k = 0; k < 2; k++) {
                    int new_i = i + di[k];
                    int new_j = j + dj[k];
                    if (new_i < rows && new_j < cols) {
                        long new_time = time + 1;
                        long entry_cost = (new_i + 1) * (new_j + 1);
                        long new_cost = cost + entry_cost;
                        if (!dp[new_i][new_j].containsKey(new_time) || dp[new_i][new_j].get(new_time) > new_cost) {
                            dp[new_i][new_j].put(new_time, new_cost);
                            pq.offer(new State(new_cost, new_i, new_j, new_time));
                        }
                    }
                }
            } else {
                long new_time = time + 1;
                long wait_cost = waitCost[i][j];
                long new_cost = cost + wait_cost;
                if (!dp[i][j].containsKey(new_time) || dp[i][j].get(new_time) > new_cost) {
                    dp[i][j].put(new_time, new_cost);
                    pq.offer(new State(new_cost, i, j, new_time));
                }
            }
        }
        return -1;
    }

    static class State implements Comparable<State> {
        long cost;
        int i;
        int j;
        long time;

        public State(long cost, int i, int j, long time) {
            this.cost = cost;
            this.i = i;
            this.j = j;
            this.time = time;
        }

        public int compareTo(State other) {
            return Long.compare(this.cost, other.cost);
        }
    }
}
